  ('dietitian-moex-10487', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '根據國人膳食營養素參考攝取量之建議，我國成年人鈣質足夠攝取量（adequate intake, AI）之建議量為： 600毫克  800毫克  1000毫克  1200毫克', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "1ecb2ba898bd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10488', 'dietitian', 'dietitian-moex-094-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '對於CAS的敘述何者有誤？', '["CAS是指中國國家標準制度", "目的在提昇農畜產品及其加工製品之品質水準", "由行政院農委會訂定完成", "其認定產品包括醃漬蔬果"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "12c7822e6b08", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094130", "c": "112", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "094", "exam_name": "094年第二次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10489', 'dietitian', 'dietitian-moex-094-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '某學校營養午餐，供應500人伙食，每人每餐繳交40元，一個月供應20餐，食物成本占售價的35%，乾料成本占食 物成本30%，則每月可採購食物費用為多少萬？', '["12", "14", "26", "28"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "12c7822e6b08", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094130", "c": "112", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "094", "exam_name": "094年第二次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
